class Product:
    def __init__(self, id, name, price, description):
        self.id = id
        self.name = name
        self.price = price
        self.description = description

    def display_details(self):
        print(f"Product ID: {self.id}")
        print(f"Name: {self.name}")
        print(f"Price: {self.price}")
        print(f"Description: {self.description}")

class Book(Product):
    def __init__(self, id, name, price, description, author, pages):
        super().__init__(id, name, price, description)
        self.author = author
        self.pages = pages

    def get_author(self):
        return self.author

    def get_page_count(self):
        return self.pages

# Do not modify the code below. This function will be called during testing.
def default_test():
    book = Book(id=1, name="Inheritance in Python", price=29.99, description="A guide to object-oriented programming", author="John Doe", pages=200)
    book.display_details()
    print(f"Author: {book.get_author()}")
    print(f"Pages: {book.get_page_count()}")
